from pathlib import Path
from subprocess import check_output

def parse_fasta(path):
    seqs={}
    name=None
    buf=[]
    for line in Path(path).read_text().splitlines():
        line=line.strip()
        if not line: continue
        if line.startswith('>'):
            if name: seqs[name]=''.join(buf).lower()
            name=line[1:]
            buf=[]
        else:
            buf.append(line)
    if name: seqs[name]=''.join(buf).lower()
    return seqs

def rc(s):
    return s.translate(str.maketrans('acgt','tgca'))[::-1]

def tm(seq):
    out=check_output(['oligotm','-tp','1','-sc','1','-mv','50','-dv','2','-n','0.8','-d','500',seq], text=True).strip()
    return float(out)
seqs=parse_fasta('/app/sequences.fasta')
inp=seqs['input']; out=seqs['output']
split=215
insert=out[split:split+(len(out)-len(inp))]
left=inp[:split]
right=inp[split:]
print('insert', insert, len(insert))
valid=[]
for nrev in range(15,46):
    annealed_rev=left[-nrev:]
    rev_primer=rc(annealed_rev)
    tm_rev=tm(rev_primer)
    if not (58 <= tm_rev <= 72):
        continue
    for nfwd in range(15,46):
        annealed_fwd=right[:nfwd]
        fwd_primer=insert + annealed_fwd
        tm_fwd=tm(annealed_fwd)
        if not (58 <= tm_fwd <= 72):
            continue
        if abs(tm_fwd - tm_rev) > 5:
            continue
        primers_concat=rc(rev_primer)+fwd_primer
        i=primers_concat.find(insert)
        if i == -1:
            continue
        ar=primers_concat[:i]
        af=primers_concat[i+len(insert):]
        if not (15 <= len(ar) <= 45 and 15 <= len(af) <= 45):
            continue
        if ar != annealed_rev or af != annealed_fwd:
            continue
        valid.append((abs(tm_fwd-tm_rev), nrev, nfwd, tm_rev, tm_fwd, rev_primer, fwd_primer, annealed_rev, annealed_fwd))
valid.sort(key=lambda x:(x[0], x[1]+x[2], x[1], x[2]))
for rec in valid[:20]:
    d,nrev,nfwd,tr,tf,rev,fwd,ar,af=rec
    print({'dTm':round(d,2),'nrev':nrev,'nfwd':nfwd,'Tm_rev':round(tr,2),'Tm_fwd':round(tf,2),'rev':rev,'fwd':fwd,'ar':ar,'af':af})
print('count', len(valid))
